import React from 'react';
export default function Questions() {
  const answers = ["A. Ngô Quyền", "B. Đinh Bộ Lĩnh", "C. Lê Hoàn", "D. Lý Thái Tổ"];
  return (
    <div className="flex flex-col gap-3">
       {answers.map((ans, index) => (
         <button key={index} className="w-full bg-yellow-100 border-2 border-yellow-600 p-4 rounded-lg hover:bg-yellow-300 text-left text-lg font-medium transition duration-200 text-yellow-900">
           {ans}
         </button>
       ))}
    </div>
  );
}
